import os
import sys

# Create symlinks from cpython-36m to cpython-311
for root, dirs, files in os.walk('sklearn'):
    for f in files:
        if 'cpython-36m' in f:
            old_path = os.path.join(root, f)
            new_f = f.replace('cpython-36m', f'cpython-{sys.version_info.major}{sys.version_info.minor}')
            new_path = os.path.join(root, new_f)
            if not os.path.exists(new_path):
                os.symlink(f, new_path)
                print(f'Created symlink: {new_path} -> {f}')
